// export default class dataBase {
import Post from '../Post'

export function openDataBase(data) {
    let openReq = indexedDB.open("Post_User_DB", 15)
    let db;
    let transaction;

    openReq.onupgradeneeded = function (e) {
        db = e.target.result;
        if (!db.objectStoreNames.contains("post")) {
            db.createObjectStore("post")
        }
        if (!db.objectStoreNames.contains("user-post-1")) {
            db.createObjectStore("user-post-1")
        }
        
    }

    openReq.onsuccess = function (e) {
        console.log("Success!");
        console.log();

        db = e.target.result;
        transaction = db.transaction(["user-post-1","user-post-2","user-post-3","user-post-4","user-post-5","user-post-6","user-post-7","user-post-8","user-post-9","user-post-10","user-post-11","user-post-12","user-post-13","user-post-14","user-post-15",],"readwrite");
        const store1 = transaction.objectStore("user-post-1");
        store1.add(Post[0], 1).onsuccess = e => console.log(e);
        store1.add(Post[1], 2).onsuccess = e => console.log(e);
        store1.add(Post[2], 3).onsuccess = e => console.log(e);
        store1.add(Post[3], 4).onsuccess = e => console.log(e);
        store1.add(Post[4], 5).onsuccess = e => console.log(e);
        store1.add(Post[5], 6).onsuccess = e => console.log(e);
        store1.add(Post[6], 7).onsuccess = e => console.log(e);
        store1.add(Post[7], 8).onsuccess = e => console.log(e);
        store1.add(Post[8], 9).onsuccess = e => console.log(e);
        store1.add(Post[9], 10).onsuccess = e => console.log(e);
        store1.add(Post[10], 11).onsuccess = e => console.log(e);
        store1.add(Post[11], 12).onsuccess = e => console.log(e);
        store1.add(Post[12], 13).onsuccess = e => console.log(e);
        store1.add(Post[13], 14).onsuccess = e => console.log(e);
        store1.add(Post[14], 15).onsuccess = e => console.log(e);

    }
    openReq.onerror = function (e) {
        console.log("Error");
        console.dir(e);
    }
}

export function readDataBase(data) {
    let openReq = indexedDB.open("Post_User_DB", 1)
    let db;
    let transaction;

    openReq.onupgradeneeded = function (e) {
        db = e.target.result;
        if (!db.objectStoreNames.contains("user-post-1")) {
            db.createObjectStore("user-post-1")
        }
    }

    openReq.onsuccess = function (e) {
        console.log("Success!");
        db = e.target.result;

        transaction = db.transaction(["user-post-1"],"readonly");
        const store = transaction.objectStore("user-post-1");

        store.openCursor().onsuccess = e => {
            const result = e.target.result;
            if (result) {
              console.log("Key", result.key)
              console.log("Data", result.value)
              result.continue()
            }
          }
    }
    openReq.onerror = function (e) {
        console.log("Error");
        console.dir(e);
    }
}
